mapper.select:
/* com.shop.mapper.biz.Receiving.selectReceivingList */ SELECT R.ID AS id , R.PRODUCT_DET_ID AS productDetId , P.ID AS prodId , P.PROD_NM AS prodNm , PD.PRODUCT_DET_SIZE AS productDetSize , PD.PRODUCT_DET_COLOR AS productDetColor , R.RECEIV_DATE AS receivDate , R.RECEIV_CNT AS receivCnt , R.PLUSMINUS AS plusMinus , R.ETC_CNTN AS etcCntn , R.UPD_USER AS updUser , R.UPD_TM AS updTm FROM TB_RECEIVING R JOIN TB_PRODUCT_DET PD ON PD.ID = R.PRODUCT_DET_ID AND PD.DEL_YN = 'N' JOIN TB_PRODUCT P ON P.ID = PD.PRODUCT_ID AND P.PARTNER_ID = #{partnerId} AND P.DEL_YN = 'N' WHERE R.DEL_YN = 'N'
AND R.RECEIV_DATE >= #{fromDate}
AND R.RECEIV_DATE < #{toDate}
AND R.PLUSMINUS = #{plusMinus}
AND P.PROD_NM LIKE CONCAT('%', #{prodNm}, '%')
ORDER BY R.ID DESC

/* com.shop.mapper.biz.Receiving.selectProductDetSearchList */ SELECT PD.ID AS productDetId , P.ID AS prodId , P.PROD_NM AS prodNm , PD.PRODUCT_DET_SIZE AS productDetSize , PD.PRODUCT_DET_COLOR AS productDetColor , COALESCE(( SELECT SUM(CASE WHEN R.PLUSMINUS = 'P' THEN R.RECEIV_CNT ELSE -R.RECEIV_CNT END) FROM TB_RECEIVING R WHERE R.PRODUCT_DET_ID = PD.ID AND R.DEL_YN = 'N' ), 0) - COALESCE(( SELECT SUM(OI.QUANTITY) FROM TB_ORDER_ITEM OI JOIN TB_ORDER O ON O.ID = OI.ORDER_ID AND O.ORDER_STATUS NOT IN ('C') WHERE OI.PRODUCT_DET_ID = PD.ID ), 0) AS stock FROM TB_PRODUCT_DET PD JOIN TB_PRODUCT P ON P.ID = PD.PRODUCT_ID AND P.PARTNER_ID = #{partnerId} AND P.DEL_YN = 'N' WHERE PD.DEL_YN = 'N'
AND P.PROD_NM LIKE CONCAT('%', #{prodNm}, '%')
ORDER BY P.PROD_NM, PD.PRODUCT_DET_COLOR, PD.PRODUCT_DET_SIZE

mapper.insert:
/* com.shop.mapper.biz.Receiving.insertReceiving */
INSERT INTO TB_RECEIVING (
      PRODUCT_DET_ID
    , RECEIV_DATE
    , RECEIV_CNT
    , PLUSMINUS
    , ETC_CNTN
    , CRE_USER
    , UPD_USER
) VALUES (
      #{productDetId}
    , #{receivDate}
    , #{receivCnt}
    , #{plusMinus}
    , #{etcCntn}
    , #{creUser}
    , #{creUser}
)

mapper.update:
/* com.shop.mapper.biz.Receiving.updateReceiving */
UPDATE TB_RECEIVING
SET
      RECEIV_DATE = #{receivDate}
    , RECEIV_CNT  = #{receivCnt}
    , PLUSMINUS   = #{plusMinus}
    , ETC_CNTN    = #{etcCntn}
    , UPD_USER    = #{updUser}
    , UPD_TM      = NOW()
WHERE ID = #{id}
  AND DEL_YN = 'N'

/* com.shop.mapper.biz.Receiving.updateReceivingIfExist */
UPDATE TB_RECEIVING
SET
UPD_TM = NOW(),
UPD_USER = #{updUser}

    , RECEIV_DATE = #{receivDate}


    , RECEIV_CNT = #{receivCnt}


    , PLUSMINUS = #{plusMinus}


    , ETC_CNTN = #{etcCntn}

WHERE ID = #{id}
AND DEL_YN = 'N'

/* com.shop.mapper.biz.Receiving.deleteReceiving */
UPDATE TB_RECEIVING
SET
      DEL_YN   = 'Y'
    , UPD_USER = #{updUser}
    , UPD_TM   = NOW()
WHERE ID = #{id}
